function getMap() return M end

function getCardData(params)
  params = params or {}
  local uuid = params["uuid"]
  if not uuid then return nil end
  local card = M.cards[uuid]
  if not card then return nil end
  return {
    name = card.name,
    image = card.image,
    uuid = card.uuid,
    slug = card.slug,
    types = card.types,
  }
end

local function randomFromPool(pool, used)
  if not pool or #pool == 0 then return nil end
  local attempts = 0
  while attempts < 50 do
    local card = pool[math.random(#pool)]
    if not used[card] then
      return card
    end
    attempts = attempts + 1
  end
  return nil
end

local function weightedRoll(weighted, used)
  if not weighted or #weighted == 0 then return nil end
  local total = 0
  for _, entry in ipairs(weighted) do
    total = total + (entry.weight or 0)
  end
  if total <= 0 then return nil end

  local attempts = 0
  while attempts < 50 do
    local roll = math.random() * total
    local running = 0
    for _, entry in ipairs(weighted) do
      running = running + (entry.weight or 0)
      if roll <= running then
        local pool = M.pools[entry.pool]
        local card = randomFromPool(pool, used)
        if card then return card end
        break
      end
    end
    attempts = attempts + 1
  end
  return nil
end

function getPool(params)
  local pools = M["pools"]
  return pools and pools[params["pool"]]
end

function getCollation(params)
  return M["collations"][params["name"]]
end

function GeneratePack(params)
  params = params or {}
  local collationName = params.collation_name or "PHANTOM_MONARCHS_8_CARD"
  local collation = M.collations[collationName]
  if not collation then
    print("Unknown collation:", collationName)
    return {}
  end

  local used = {}
  local cards = {}
  for _, slot in ipairs(collation.slots or {}) do
    local card = nil
    if slot.weighted then
      card = weightedRoll(slot.weighted, used)
    elseif slot.pool then
      card = randomFromPool(M.pools[slot.pool], used)
    end
    if card then
      used[card] = true
      table.insert(cards, card)
    end
  end
  return cards
end

function onLoad(saved_data)
  Global.setVar('GA_CollationData', self)
  Global.setVar('GA_CollationLibrary', self)
end
